// Act harness: runs the full GitHub Actions workflow through `act push --rm`
// inside a throwaway git repo built from the project sources, then asserts on
// exact values in the captured output.
//
// The workflow contains four test cases (basic, with-exclude, with-include,
// too-big) as distinct steps — we run act once and parse markers from the
// combined log, so the whole test matrix costs exactly one act invocation.
//
// The full log (plus a per-test-case summary) is persisted to
// act-result.txt in the project root so the runner can attach it.
import { describe, test, expect, beforeAll, afterAll } from "bun:test";
import { spawnSync } from "node:child_process";
import {
  mkdtempSync,
  mkdirSync,
  cpSync,
  writeFileSync,
  rmSync,
  existsSync,
} from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";

const ROOT = join(import.meta.dir, "..");
const ACT_RESULT = join(ROOT, "act-result.txt");
const TIMEOUT_MS = 10 * 60 * 1000; // act + first-run docker image pull can be slow

let actLog = "";
let actExit = -1;
let actWorkdir = "";

// Assemble a scratch repo with just the files act needs, then run act once.
beforeAll(() => {
  actWorkdir = mkdtempSync(join(tmpdir(), "env-matrix-act-"));

  // Copy project sources. We do NOT copy node_modules or .git — act will
  // initialise a fresh one and `bun run` resolves local .ts files directly.
  const copy = (rel: string) => {
    const src = join(ROOT, rel);
    if (!existsSync(src)) return;
    cpSync(src, join(actWorkdir, rel), { recursive: true });
  };
  for (const entry of [
    "src",
    "tests",
    "fixtures",
    ".github",
    "package.json",
    "tsconfig.json",
    ".actrc",
  ]) {
    copy(entry);
  }

  // act needs a git repo + at least one commit to treat the tree as a valid
  // push event. Suppress hook invocation so global user hooks don't trip.
  const git = (args: string[]) =>
    spawnSync("git", args, { cwd: actWorkdir, encoding: "utf8" });
  git(["init", "-q", "-b", "main"]);
  git(["config", "user.email", "harness@test.local"]);
  git(["config", "user.name", "Harness"]);
  git(["config", "commit.gpgsign", "false"]);
  git(["add", "-A"]);
  const commit = git(["commit", "-q", "-m", "harness fixture"]);
  if (commit.status !== 0) {
    throw new Error(`git commit failed: ${commit.stderr}`);
  }

  // Run act from the scratch repo. --rm cleans up containers, --pull=false
  // reuses the local act-ubuntu-pwsh:latest image that the benchmark rigs.
  const act = spawnSync(
    "act",
    ["push", "--rm", "--pull=false", "--container-architecture", "linux/amd64"],
    {
      cwd: actWorkdir,
      encoding: "utf8",
      maxBuffer: 64 * 1024 * 1024,
      timeout: TIMEOUT_MS,
    },
  );
  actLog = (act.stdout ?? "") + "\n" + (act.stderr ?? "");
  actExit = act.status ?? -1;

  writeFileSync(
    ACT_RESULT,
    [
      `=== act push --rm (combined stdout+stderr) ===`,
      `exit code: ${actExit}`,
      `scratch repo: ${actWorkdir}`,
      ``,
      actLog,
    ].join("\n"),
  );
}, TIMEOUT_MS);

afterAll(() => {
  if (actWorkdir && existsSync(actWorkdir)) {
    rmSync(actWorkdir, { recursive: true, force: true });
  }
});

describe("act run", () => {
  test("act exits 0", () => {
    if (actExit !== 0) {
      // Dump the tail of the log so failures are diagnosable from the test
      // output alone (the full log also lives in act-result.txt).
      console.error(actLog.slice(-4000));
    }
    expect(actExit).toBe(0);
  });

  test("both jobs report success", () => {
    // act prints `Job succeeded` for every successful job.
    const successMatches = [...actLog.matchAll(/Job succeeded/g)];
    expect(successMatches.length).toBeGreaterThanOrEqual(2);
  });
});

describe("per-case assertions parsed from act log", () => {
  test("basic case: total=4", () => {
    expect(actLog).toContain("=== CASE basic ===");
    expect(actLog).toContain("BASIC_TOTAL=4");
  });

  test("with-exclude case: total=7 (3x3 minus two excluded pairs)", () => {
    expect(actLog).toContain("=== CASE with-exclude ===");
    expect(actLog).toContain("EXCLUDE_TOTAL=7");
  });

  test("with-include case: total=2 and macos entry appears", () => {
    expect(actLog).toContain("=== CASE with-include ===");
    expect(actLog).toContain("INCLUDE_TOTAL=2");
    expect(actLog).toContain("macos-latest");
  });

  test("too-big case: CLI exits 2 on maxSize violation", () => {
    expect(actLog).toContain("=== CASE too-big ===");
    expect(actLog).toContain("TOO_BIG_EXIT=2");
  });
});

